import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Initialize a dynamic buffer
        char[] buffer = new char[10];

        // Check if user input exceeds buffer size
        if (userInput.length() > buffer.length) {
            // Resize buffer dynamically to accommodate user input
            buffer = Arrays.copyOf(buffer, userInput.length());
        }

        userInput.getChars(0, userInput.length(), buffer, 0); // Copy user input into buffer

        System.out.println("Buffer contents: " + new String(buffer));

        scanner.close();
    }
}

